/**
 * Chat-context build integrity (CHAT-03 / AI-SPEC §5.6 / D-06..D-11 / D-04)
 *
 * Asserts invariants on the generated src/data/portfolio-context.json:
 *   - All 6 active project slugs present (D-04 allow-list)
 *   - Projects/7 (MULTI-DEX) NOT present (D-04 exclusion)
 *   - Per-project caseStudy + extendedReference fields present and non-empty (D-01/D-02)
 *   - Token-count floor >= 4096 (AI-SPEC §3 pitfall #1 — Haiku 4.5 cache minimum)
 *   - Static split keys + generated keys BOTH present (D-08)
 *
 * Target artifact is generated by scripts/build-chat-context.mjs (Plan 14-02).
 * Before Plan 14-02 ships, most assertions are RED — this is the Wave 0 target.
 */
import { describe, it, expect } from "vitest";
import portfolioContext from "../../src/data/portfolio-context.json";

const EXPECTED_SLUGS = [
  "clipify",
  "daytrade",
  "nfl-predict",
  "optimize-ai",
  "seatwatch",
  "solsniper",
];

const PROJECTS_7_REGEXES: readonly RegExp[] = [
  /MULTI[- ]?DEX/i,
  /multi[- ]?dex/i,
  /crypto trader/i,
  /crypto arbitrage/i,
];

// Cheap char-based token estimator (matches generator's estimateTokens helper).
// Haiku 4.5 cache minimum is 4096 tokens; char / 4 is the SDK's conservative rule.
const MIN_TOKENS = 4096;

describe("Chat Context Integrity (CHAT-03 / §5.6)", () => {
  it("contains the 6 expected project slugs (D-04 allow-list)", () => {
    const slugs = (portfolioContext.projects as Array<{ page: string }>)
      .map((p) => p.page.replace("/projects/", ""))
      .sort();
    expect(slugs).toEqual(EXPECTED_SLUGS);
  });

  it("projects[] has exactly 6 entries (no Projects/7 leak)", () => {
    expect((portfolioContext.projects as unknown[]).length).toBe(6);
  });

  it("no Projects/7 content leaks into the merged JSON (D-04 regex banlist)", () => {
    const serialized = JSON.stringify(portfolioContext);
    const hits: string[] = [];
    for (const regex of PROJECTS_7_REGEXES) {
      if (regex.test(serialized)) {
        hits.push(regex.toString());
      }
    }
    expect(hits).toEqual([]);
  });

  it("every project has a non-empty caseStudy field (D-01 MDX body)", () => {
    const failures: string[] = [];
    for (const project of portfolioContext.projects as Array<{
      page: string;
      caseStudy?: string;
    }>) {
      if (!project.caseStudy || project.caseStudy.trim().length < 100) {
        failures.push(`${project.page}: caseStudy missing or <100 chars`);
      }
    }
    expect(failures).toEqual([]);
  });

  it("every project has a non-empty extendedReference.content field (D-02 Projects/*.md below-fence)", () => {
    const failures: string[] = [];
    for (const project of portfolioContext.projects as Array<{
      page: string;
      extendedReference?: { content?: string; truncated?: boolean };
    }>) {
      if (
        !project.extendedReference ||
        !project.extendedReference.content ||
        project.extendedReference.content.trim().length < 100
      ) {
        failures.push(
          `${project.page}: extendedReference.content missing or <100 chars`
        );
      }
    }
    expect(failures).toEqual([]);
  });

  it("total serialized size >= 4096 tokens (Haiku 4.5 cache floor; AI-SPEC §3 pitfall #1)", () => {
    const serialized = JSON.stringify(portfolioContext);
    const estimatedTokens = Math.ceil(serialized.length / 4);
    expect(
      estimatedTokens,
      `estimated tokens ${estimatedTokens} below Haiku 4.5 floor ${MIN_TOKENS}; cache would silently disable`
    ).toBeGreaterThanOrEqual(MIN_TOKENS);
  });

  it("contains all D-08 static identity keys (personal, education, skills, contact, siteStack)", () => {
    expect(portfolioContext).toHaveProperty("personal");
    expect(portfolioContext).toHaveProperty("education");
    expect(portfolioContext).toHaveProperty("skills");
    expect(portfolioContext).toHaveProperty("contact");
    expect(portfolioContext).toHaveProperty("siteStack");
  });

  it("contains all D-08 generated keys (projects, experience, about)", () => {
    expect(portfolioContext).toHaveProperty("projects");
    expect(portfolioContext).toHaveProperty("experience");
    expect(portfolioContext).toHaveProperty("about");
    const about = (portfolioContext as Record<string, unknown>).about as
      | Record<string, unknown>
      | undefined;
    expect(about).toBeDefined();
    expect(about).toHaveProperty("intro");
    expect(about).toHaveProperty("p1");
    expect(about).toHaveProperty("p2");
    expect(about).toHaveProperty("p3");
  });

  it("Daytrade extendedReference.truncated is true (D-06 — Daytrade 7,246 words exceeds 5k cap)", () => {
    const daytrade = (
      portfolioContext.projects as Array<{
        page: string;
        extendedReference?: { truncated?: boolean; truncationMarker?: string };
      }>
    ).find((p) => p.page === "/projects/daytrade");
    expect(daytrade).toBeDefined();
    expect(daytrade?.extendedReference?.truncated).toBe(true);
    expect(daytrade?.extendedReference?.truncationMarker).toContain(
      "see /projects/daytrade"
    );
  });
});
